SELECT count(*) FROM title, movie_keyword, movie_info, info_type, keyword, cast_info, char_name, movie_companies WHERE movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND movie_companies.movie_id = title.id;